import styles from "./styles.module.scss";
import Image from "next/image";
import Link from "next/link";
import { motion } from "framer-motion";

const fadeInAnimationVariants = {
  initial: {
    opacity: 0,
    y: 20,
  },
  animate: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.8,
      ease: "easeInOut",
    },
  },
};

interface IntroductionContentItem {
  type: "h2" | "p" | "image" | "cta";
  className: string;
  variants: typeof fadeInAnimationVariants;
  transition: { delay: number };
  content?: string; // Only for h2 and p
  src?: string;     // Only for image
  alt?: string;     // Only for image
  width?: number;    // Only for image
  height?: number;   // Only for image
  imageClassName?: string; // Only for image
  href?: string;      // Only for cta
  buttonClassName?: string; // Only for cta
  buttonText?: string;  // Only for cta
}

const introductionContent: IntroductionContentItem[] = [
  {
    type: "h2",
    className: styles.introductionTitle,
    variants: fadeInAnimationVariants,
    transition: { delay: 0.2 },
    content: "Khám Phá Thế Giới Công Nghệ Di Động Tuyệt Đỉnh!",
  },
  {
    type: "p",
    className: styles.introductionDescription,
    variants: fadeInAnimationVariants,
    transition: { delay: 0.4 },
    content:
      "Chào mừng bạn đến với [Tên Website/Thương Hiệu] - nơi hội tụ những chiếc điện thoại thông minh mới nhất, mạnh mẽ nhất và phong cách nhất. Chúng tôi tự hào mang đến cho bạn trải nghiệm mua sắm trực tuyến hoàn hảo, với sự đa dạng về sản phẩm, chất lượng dịch vụ hàng đầu và mức giá cạnh tranh nhất trên thị trường.",
  },
  {
    type: "image",
    className: styles.introductionImageWrapper,
    variants: fadeInAnimationVariants,
    transition: { delay: 0.6 },
    src: "/qc1.webp",
    alt: "Điện thoại thông minh",
    width: 500,
    height: 300,
    imageClassName: styles.introductionImage,
  },
  {
    type: "cta",
    className: styles.introductionCTA,
    variants: fadeInAnimationVariants,
    transition: { delay: 0.8 },
    href: "/qc1.webp",
    buttonClassName: styles.shopNowButton,
    buttonText: "Khám Phá Ngay!",
  },
];

export default function IntroductionSection() {
  return (
    <section
      className={styles.introductionSection}
    >
      <div className={styles.introductionContent}>
        {introductionContent.map((item, index) => {
          const motionProps = {
            key: index,
            className: item.className,
            variants: item.variants,
            initial: "initial",
            animate: "animate",
            transition: item.transition,
          };

          switch (item.type) {
            case "h2":
              return (
                <motion.h2 {...motionProps}>
                  {item.content}
                </motion.h2>
              );
            case "p":
              return (
                <motion.p {...motionProps}>
                  {item.content}
                </motion.p>
              );
            case "image":
              return (
                <motion.div {...motionProps}>
                  <Image
                    src={item.src ?? ""}
                    alt={item.alt ?? "Image"}
                    width={item.width!}
                    height={item.height!}
                    className={item.imageClassName}
                  />
                </motion.div>
              );
            case "cta":
              return (
                <motion.div {...motionProps}>
                  <Link href={item.href ?? "#"} className={item.buttonClassName}>
                    {item.buttonText}
                  </Link>
                </motion.div>
              );
            default:
              return null;
          }
        })}
      </div>
    </section>
  );
}